class StateModel:
    def __init__(self, width, height, templates):
        self.width = width
        self.height = height
        self.templates = templates
        self.belief_grid = [[0.0 for _ in range(width)] for _ in range(height)]
        self.possible_placements = []
        self._initialize_placements()

