        for dr, dc in template:
            nr, nc = r + dr, c + dc
            if not (0 <= nr < self.height and 0 <= nc < self.width):
                return False
        return True

    def _get_cells(self, template, r, c):
        return [(r + dr, c + dc) for dr, dc in template]

